128→                  value={url}
129→                  onChange={(e) => setUrl(e.target.value)}
130→                  placeholder="https://votre-site.com/blog/article-existant"
131→                  className="w-full bg-black/40 border border-white/10 rounded-lg p-3 text-white placeholder-gray-600 focus:border-pink-500/50 outline-none transition-colors"
132→                />
133→              </div>
134→
135→              <div className="pt-4 border-t border-white/5">
136→                <div className="flex justify-between items-center mb-4 text-xs text-gray-500">
137→                  <span>Coût Brief</span>
